#include <stdio.h>

int main() {
    int t;
    scanf("%d", & t); // Read the number of test cases
    while (t--) {
        long long k = 0, n;
        scanf("%lld", & n); // Read the number of elements in the test case
        for (int i = 0; i < n; i++) {
            long long x;
            scanf("%lld", & x); // Read each element
            x *= 2; // Multiply by 2
            k ^= x; // Perform XOR operation
        }
        printf("%lld\n", k); // Output the result for the test case
    }
    return 0;
}

code.Java:
import java.util.Scanner;

class Codechef {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt(); // Read the number of test cases

        while (t--> 0) {
            long k = 0;
            int n = scanner.nextInt(); // Read the size of the array
            long[] arr = new long[n]; // Array to store the integers

            for (int i = 0; i < n; i++) {
                arr[i] = scanner.nextLong() * 2; // Read and double the input value
                k ^= arr[i]; // XOR with the doubled value
            }

            System.out.println(k); // Print the result for the test case
        }

        scanner.close(); // Close the scanner
    }
}
